import { useState, useEffect } from 'react'
import { useLang } from '../i18n/LangContext'
import { useCart } from '../context/CartContext'
import axios from 'axios'

const C = { bordeaux:'#6B1515', beige:'#F5E6C8', or:'#C4922A', beige2:'#FAF0DC' }

export default function CatalogueFemmes() {
  const { t } = useLang()
  const [produits, setProduits] = useState([])
  const [vue, setVue] = useState('grille') // grille ou liste
  const [chargement, setChargement] = useState(true)

  useEffect(() => {
    axios.get('http://localhost:8000/api/products?gender=femme')
      .then(res => {
        setProduits(res.data.data)
        setChargement(false)
      })
      .catch(() => setChargement(false))
  }, [])

  return (
    <div style={{ background: C.beige2, minHeight:'100vh', padding:'30px 24px', fontFamily:'Georgia,serif' }}>

      {/* Titre */}
      <h1 style={{ textAlign:'center', color: C.bordeaux, fontWeight:'normal', marginBottom:'6px' }}>
        {t('femmes')}
      </h1>
      <div style={{ width:'50px', height:'2px', background: C.or, margin:'0 auto 24px' }}></div>

      {/* Boutons vue grille/liste */}
      <div style={{ display:'flex', justifyContent:'flex-end', gap:'8px', marginBottom:'20px' }}>
        <button onClick={() => setVue('grande')}
          style={{ background: vue==='grande' ? C.bordeaux : 'transparent', color: vue==='grande' ? C.beige : C.bordeaux, border:`1px solid ${C.bordeaux}`, padding:'6px 10px', borderRadius:'4px', cursor:'pointer' }}>
          ▦
        </button>
        <button onClick={() => setVue('grille')}
          style={{ background: vue==='grille' ? C.bordeaux : 'transparent', color: vue==='grille' ? C.beige : C.bordeaux, border:`1px solid ${C.bordeaux}`, padding:'6px 10px', borderRadius:'4px', cursor:'pointer' }}>
          ⊞
        </button>
        <button onClick={() => setVue('liste')}
          style={{ background: vue==='liste' ? C.bordeaux : 'transparent', color: vue==='liste' ? C.beige : C.bordeaux, border:`1px solid ${C.bordeaux}`, padding:'6px 10px', borderRadius:'4px', cursor:'pointer' }}>
          ☰
        </button>
      </div>

      {/* Chargement */}
      {chargement && (
        <p style={{ textAlign:'center', color: C.bordeaux }}>Chargement...</p>
      )}

      {/* Grille produits */}
      {!chargement && (
        <div style={{
          display: 'grid',
          gridTemplateColumns: vue === 'grande' ? 'repeat(2, 1fr)'
                             : vue === 'grille'  ? 'repeat(3, 1fr)'
                             : '1fr',
          gap: '20px'
        }}>
          {produits.map(produit => (
            <CarteProduit key={produit.id} produit={produit} vue={vue} />
          ))}
        </div>
      )}

      {/* Aucun produit */}
      {!chargement && produits.length === 0 && (
        <p style={{ textAlign:'center', color:'#8B5520', marginTop:'40px' }}>
          Aucun produit disponible
        </p>
      )}
    </div>
  )
}

function CarteProduit({ produit, vue }) {
  const [ml, setMl] = useState(30)
  const { ajouterAuPanier } = useCart()
  const { t } = useLang()

  const prix = produit[`price_${ml}ml`] || produit.price_30ml

  // Vue liste horizontale
  if (vue === 'liste') {
    return (
      <div style={{ display:'flex', gap:'16px', background:'#fff', borderRadius:'8px', overflow:'hidden', border:'1px solid #e0c8a0' }}>
        <img
          src={produit.image_url}
          alt={produit.name}
          style={{ width:'120px', height:'120px', objectFit:'cover' }}
          onError={e => e.target.src = 'https://placehold.co/120x120/F5E6C8/6B1515?text=Parfum'}
        />
        <div style={{ padding:'14px', flex:1, display:'flex', flexDirection:'column', justifyContent:'center' }}>
          <h3 style={{ color: '#6B1515', fontWeight:'normal', fontSize:'16px', marginBottom:'6px' }}>{produit.name}</h3>
          <div style={{ display:'flex', gap:'6px', marginBottom:'8px' }}>
            {[30, 50, 100].map(v => produit[`price_${v}ml`] && (
              <button key={v} onClick={() => setMl(v)}
                style={{ background: ml===v ? '#6B1515' : '#F5E6C8', color: ml===v ? '#F5E6C8' : '#6B1515', border:'1px solid #6B1515', padding:'3px 8px', fontSize:'11px', borderRadius:'3px', cursor:'pointer' }}>
                {v}ml
              </button>
            ))}
          </div>
          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
            <span style={{ color:'#C4922A', fontSize:'18px', fontWeight:'bold' }}>{prix}.00 dh</span>
            <button onClick={() => ajouterAuPanier(produit, ml)}
              style={{ background:'#6B1515', color:'#F5E6C8', border:'none', padding:'8px 16px', borderRadius:'4px', fontSize:'12px', cursor:'pointer', fontFamily:'Georgia,serif' }}>
              {t('ajouter')}
            </button>
          </div>
        </div>
      </div>
    )
  }

  // Vue grille (grande ou normale)
  return (
    <div style={{ background:'#fff', borderRadius:'8px', overflow:'hidden', border:'1px solid #e0c8a0' }}>
      {/* Image grande */}
      <div style={{ position:'relative', overflow:'hidden' }}>
        <img
          src={produit.image_url}
          alt={produit.name}
          style={{ width:'100%', height: vue==='grande' ? '320px' : '220px', objectFit:'cover', display:'block' }}
          onError={e => e.target.src = 'https://placehold.co/400x300/F5E6C8/6B1515?text=Parfum'}
        />
      </div>

      {/* Infos */}
      <div style={{ padding:'14px 16px' }}>
        <h3 style={{ color:'#3d1010', fontWeight:'normal', fontSize:'15px', marginBottom:'6px', textAlign:'center' }}>
          {produit.name}
        </h3>

        {/* Sélecteur ml */}
        <div style={{ display:'flex', gap:'6px', justifyContent:'center', marginBottom:'10px' }}>
          {[30, 50, 100].map(v => produit[`price_${v}ml`] && (
            <button key={v} onClick={() => setMl(v)}
              style={{ background: ml===v ? '#6B1515' : '#F5E6C8', color: ml===v ? '#F5E6C8' : '#6B1515', border:'1px solid #C4922A', padding:'3px 10px', fontSize:'11px', borderRadius:'3px', cursor:'pointer' }}>
              {v}ml
            </button>
          ))}
        </div>

        {/* Prix */}
        <p style={{ color:'#C4922A', fontSize:'18px', fontWeight:'bold', textAlign:'center', marginBottom:'12px' }}>
          {prix}.00 dh
        </p>

        {/* Bouton ajouter */}
        <button onClick={() => ajouterAuPanier(produit, ml)}
          style={{ width:'100%', background:'#6B1515', color:'#F5E6C8', border:'none', padding:'10px', borderRadius:'4px', fontSize:'13px', cursor:'pointer', fontFamily:'Georgia,serif' }}>
          + {t('ajouter')}
        </button>
      </div>
    </div>
  )
}
